.oak-marketing {
font-family: var(--oak-mono);
font-size: 14.5px;
line-height: 1.55;
color: var(--hp-ink);
.oak-marketing a { text-decoration: none; }
main.oak-marketing { flex: 1; }
/* ── layout ─────────────────────────────────────────────────────── */
.hp-wrap { max-width: 1200px; margin: 0 auto; padding: 0 28px; }
.hp-wrap-narrow { max-width: 860px; margin: 0 auto; padding: 0 28px; }
@media (max-width: 640px) {
.hp-wrap, .hp-wrap-narrow { padding: 0 16px; }
/* ── content sections ────────────────────────────────────────────── */
.hp-s { padding: 72px 0 64px; border-bottom: 1px solid var(--hp-line); }
.hp-s:last-child { border-bottom: 0; }
.hp-s-tight { padding: 48px 0; }
.hp-eyebrow {
display: inline-flex; align-items: center; gap: 10px;
color: var(--hp-ink-mute); font-size: 11.5px;
text-transform: lowercase; letter-spacing: 0.04em; margin-bottom: 14px;
.hp-eyebrow::before {
content: ''; display: inline-block; width: 22px; height: 1px;
background: var(--hp-line-strong);
.hp-marker { color: var(--hp-moss); font-weight: 600; }
.hp-eyebrow-cy .hp-marker { color: var(--hp-cyan-2); }
.hp-eyebrow-mg .hp-marker { color: var(--hp-magenta-2); }
.hp-eyebrow-am .hp-marker { color: var(--hp-amber-2); }
/* ── typography (marketing) ─────────────────────────────────────── */
.hp-h1 {
font-family: var(--oak-mono);
font-size: clamp(32px, 4.2vw, 50px);
line-height: 1.08; font-weight: 600; letter-spacing: -0.025em;
color: var(--hp-ink); margin: 0 0 18px;
.hp-h2 {
font-family: var(--oak-mono);
font-size: clamp(24px, 3vw, 34px); line-height: 1.14;
font-weight: 600; letter-spacing: -0.02em; margin: 0 0 14px;
color: var(--hp-ink);
.hp-h3 {
font-family: var(--oak-mono);
font-size: 17px; font-weight: 600; letter-spacing: -0.01em;
color: var(--hp-ink); margin: 0 0 8px;
.hp-a-moss { color: var(--hp-moss); }
.hp-a-cy { color: var(--hp-cyan-2); }
.hp-a-mg { color: var(--hp-magenta-2); }
.hp-a-am { color: var(--hp-amber-2); }
.hp-a-vm { color: var(--hp-vermilion); }
.hp-lede {
color: var(--hp-ink-soft); font-size: 15.5px; line-height: 1.7;
max-width: 60ch; margin: 0 0 28px;
.hp-sub {
color: var(--hp-ink-soft); max-width: 64ch;
font-size: 14.5px; line-height: 1.7; margin: 0 0 32px;
.oak-marketing code,
.hp-sub code, .hp-lede code, .hp-prose code {
background: var(--hp-paper-2); padding: 1px 6px; border-radius: 0;
font-size: 0.92em; font-family: 'JetBrains Mono', monospace;
color: var(--hp-ink);
.hp-prose { color: var(--hp-ink-soft); font-size: 14px; line-height: 1.7; max-width: 70ch; }
.hp-prose > * + * { margin-top: 14px; }
.hp-prose strong, .hp-prose b { color: var(--hp-ink); font-weight: 600; }
.hp-prose a { color: var(--hp-moss); border-bottom: 1px solid color-mix(in oklch, var(--hp-moss) 40%, transparent); }
.hp-prose a:hover { border-bottom-color: var(--hp-moss); }
.hp-prose ul, .hp-prose ol { padding-left: 22px; }
.hp-prose ul li, .hp-prose ol li { margin-top: 4px; }
.hp-prose ul { list-style: none; padding-left: 0; }
.hp-prose ul > li { position: relative; padding-left: 18px; }
.hp-prose ul > li::before {
content: '›'; position: absolute; left: 4px; top: 0;
color: var(--hp-moss); font-weight: 600;
.hp-prose h2 {
font-family: var(--oak-mono);
font-size: 18px; font-weight: 600; color: var(--hp-ink);
margin-top: 28px; margin-bottom: 6px; letter-spacing: -0.01em;
.hp-prose h3 {
font-family: var(--oak-mono);
font-size: 14.5px; font-weight: 600; color: var(--hp-ink);
margin-top: 20px; margin-bottom: 4px;
/* ── CTA / buttons (marketing) ──────────────────────────────────── */
.hp-cta-row { display: flex; flex-wrap: wrap; gap: 10px; align-items: center; }
.hp-btn {
display: inline-flex; align-items: center; gap: 8px;
padding: 9px 16px; border-radius: var(--hp-radius);
font-size: 13px; font-weight: 500;
border: 1px solid transparent;
transition: transform 0.06s, background 0.12s, border-color 0.12s, color 0.12s;
cursor: pointer; text-decoration: none;
.hp-btn:active { transform: translateY(1px); }
.hp-btn-arrow { width: 14px; height: 14px; transition: transform 0.12s; }
.hp-btn:hover .hp-btn-arrow { transform: translateX(2px); }
.hp-btn-primary {
background: var(--hp-ink); color: var(--hp-paper); font-weight: 600;
border-color: var(--hp-ink);
.hp-btn-primary:hover {
background: color-mix(in oklch, var(--hp-ink) 86%, var(--hp-paper));
color: var(--hp-paper);
.hp-btn-ink {
background: var(--hp-ink); color: var(--hp-paper);
border-color: var(--hp-ink);
.hp-btn-ink:hover { background: color-mix(in oklch, var(--hp-ink) 86%, var(--hp-paper)); }
.hp-btn-outline {
background: transparent; color: var(--hp-ink);
border-color: var(--hp-line-strong);
.hp-btn-outline:hover { background: var(--hp-paper-2); }
.hp-btn-ghost {
background: transparent; color: var(--hp-ink-soft);
border-color: transparent;
.hp-btn-ghost:hover { color: var(--hp-ink); background: var(--hp-paper-2); }
.hp-kbd {
display: inline-block; padding: 1px 6px;
background: var(--hp-paper-2); border: 1px solid var(--hp-line-strong);
border-radius: 0; color: var(--hp-ink);
font-family: 'JetBrains Mono', monospace; font-size: 11.5px;
.hp-tag {
display: inline-block; padding: 2px 8px; border-radius: 0;
background: var(--hp-paper-2); color: var(--hp-ink-soft);
font-size: 11px;
border: 1px solid var(--hp-line);
.hp-tag-moss { color: var(--hp-moss); border-color: color-mix(in oklch, var(--hp-moss) 30%, var(--hp-line)); background: color-mix(in oklch, var(--hp-moss) 6%, var(--hp-paper)); }
.hp-tag-cy { color: var(--hp-cyan-2); border-color: color-mix(in oklch, var(--hp-cyan) 30%, var(--hp-line)); background: color-mix(in oklch, var(--hp-cyan) 6%, var(--hp-paper)); }
.hp-tag-mg { color: var(--hp-magenta-2); border-color: color-mix(in oklch, var(--hp-magenta) 30%, var(--hp-line)); background: color-mix(in oklch, var(--hp-magenta) 6%, var(--hp-paper)); }
.hp-tag-am { color: var(--hp-amber-2); border-color: color-mix(in oklch, var(--hp-amber) 30%, var(--hp-line)); background: color-mix(in oklch, var(--hp-amber) 8%, var(--hp-paper)); }
/* ── feature cards ───────────────────────────────────────────────── */
.hp-triptych { display: grid; grid-template-columns: repeat(3, 1fr); gap: 16px; }
@media (max-width: 880px) { .hp-triptych { grid-template-columns: 1fr; } }
.hp-pair { display: grid; grid-template-columns: repeat(2, 1fr); gap: 16px; }
@media (max-width: 720px) { .hp-pair { grid-template-columns: 1fr; } }
.hp-card {
border: 1px solid var(--hp-line); background: var(--hp-paper);
border-radius: var(--hp-radius); overflow: hidden;
transition: transform 0.18s, box-shadow 0.18s, border-color 0.18s;
.hp-card:hover { transform: translateY(-2px); box-shadow: var(--hp-shadow); border-color: var(--hp-line-strong); }
.hp-card-static:hover { transform: none; box-shadow: none; border-color: var(--hp-line); }
.hp-card-hd {
display: flex; align-items: center; justify-content: space-between;
padding: 11px 16px; border-bottom: 1px solid var(--hp-line);
background: var(--hp-paper-2); font-size: 11.5px; color: var(--hp-ink-mute);
.hp-card-lft { display: flex; align-items: center; gap: 8px; }
.hp-sigil { font-weight: 600; }
.hp-c-moss .hp-sigil, .hp-c-moss .hp-pk { color: var(--hp-moss); }
.hp-c-cyan .hp-sigil, .hp-c-cyan .hp-pk { color: var(--hp-cyan-2); }
.hp-c-magenta .hp-sigil, .hp-c-magenta .hp-pk { color: var(--hp-magenta-2); }
.hp-c-amber .hp-sigil, .hp-c-amber .hp-pk { color: var(--hp-amber-2); }
.hp-badge { font-size: 10px; padding: 1px 6px; border-radius: 0; background: var(--hp-paper-3); color: var(--hp-ink-soft); }
.hp-card-bd { padding: 18px 18px 20px; }
.hp-card-bd h3 {
margin: 0 0 8px;
font-family: var(--oak-mono);
font-size: 16px; font-weight: 600; letter-spacing: -0.01em;
color: var(--hp-ink);
.hp-card-bd p { margin: 0 0 12px; color: var(--hp-ink-soft); font-size: 13.5px; line-height: 1.65; }
.hp-card-bd p:last-child { margin-bottom: 0; }
.hp-preview { border-top: 1px dashed var(--hp-line); padding-top: 14px; font-size: 12px; color: var(--hp-ink-soft); }
.hp-pl { display: block; }
.hp-pk { font-weight: 600; }
/* ── terminal / code blocks ────────────────────────────────────── */
.hp-term {
border: 1px solid var(--hp-term-line-2); border-radius: var(--hp-radius);
background: linear-gradient(180deg, var(--hp-term-bg-2), var(--hp-term-bg));
color: var(--hp-term-ink);
overflow: hidden;
.hp-term-hd {
display: flex; align-items: center; gap: 8px;
padding: 8px 12px; border-bottom: 1px solid var(--hp-term-line);
font-size: 11px; color: var(--hp-term-ink-mute);
.hp-term-dots { display: inline-flex; gap: 6px; }
.hp-term-dots span {
display: inline-block; width: 8px; height: 8px; border-radius: 50%;
.hp-term-dots .hp-dot-r { background: #e26d6d; }
.hp-term-dots .hp-dot-y { background: #d8b148; }
.hp-term-dots .hp-dot-g { background: #5fa86a; }
.hp-term-title { margin-left: 6px; color: var(--hp-term-ink-mute); }
.hp-term-body {
padding: 14px 16px; font-family: 'JetBrains Mono', monospace;
font-size: 13px; line-height: 1.7; overflow-x: auto;
.hp-term-body .hp-prompt { color: var(--hp-moss-2); user-select: none; margin-right: 8px; }
.hp-term-body .hp-arg { color: var(--hp-cyan); }
.hp-term-body .hp-pipe { color: var(--hp-magenta); }
.hp-term-body .hp-cmt { color: var(--hp-term-ink-mute); }
.hp-term-body .hp-ok { color: var(--hp-moss-2); }
.hp-term-body .hp-warn { color: var(--hp-amber-2); }
.hp-term-body .hp-err { color: var(--hp-vermilion); }
.hp-term-body pre { margin: 0; white-space: pre-wrap; }
.hp-term-body .hp-ln { display: block; white-space: pre-wrap; }
/* ── stats grid ──────────────────────────────────────────────── */
.hp-stats {
display: grid;
grid-template-columns: repeat(auto-fit, minmax(160px, 1fr));
gap: 10px;
.hp-stat {
border: 1px solid var(--hp-line); border-radius: var(--hp-radius);
padding: 14px 16px; background: var(--hp-paper);
.hp-stat-label {
font-size: 10.5px; color: var(--hp-ink-mute);
text-transform: lowercase; letter-spacing: 0.04em;
.hp-stat-val {
font-family: var(--oak-mono);
font-size: 22px; font-weight: 600; letter-spacing: -0.02em;
margin-top: 2px; color: var(--hp-ink);
.hp-stat-unit { font-size: 13px; color: var(--hp-ink-mute); margin-left: 3px; }
.hp-sv-moss { color: var(--hp-moss); }
.hp-sv-cy { color: var(--hp-cyan-2); }
.hp-sv-mg { color: var(--hp-magenta-2); }
.hp-sv-am { color: var(--hp-amber-2); }
/* ── definition lists (FAQ-style) ────────────────────────────── */
.hp-dl { display: grid; grid-template-columns: 1fr 1fr; gap: 28px 40px; }
@media (max-width: 700px) { .hp-dl { grid-template-columns: 1fr; } }
.hp-dl-q {
font-family: var(--oak-mono);
font-size: 13px; font-weight: 600; color: var(--hp-ink);
margin-bottom: 6px;
.hp-dl-q::before {
content: '// '; color: var(--hp-ink-mute); font-weight: 400;
.hp-dl-a { font-size: 13px; color: var(--hp-ink-soft); line-height: 1.65; }
.hp-dl-a a { color: var(--hp-moss); border-bottom: 1px solid color-mix(in oklch, var(--hp-moss) 40%, transparent); }
.hp-dl-a a:hover { border-bottom-color: var(--hp-moss); }
/* ── corners / ascii flourish ───────────────────────────────── */
.hp-corners {
position: absolute; inset: 18px; pointer-events: none;
color: var(--hp-ink-mute); opacity: 0.45; font-size: 14px;
font-family: 'JetBrains Mono', monospace;
.hp-corners .hp-tl,
.hp-corners .hp-tr,
.hp-corners .hp-bl,
.hp-corners .hp-br { position: absolute; }
.hp-corners .hp-tl { top: 0; left: 0; }
.hp-corners .hp-tr { top: 0; right: 0; }
.hp-corners .hp-bl { bottom: 0; left: 0; }
.hp-corners .hp-br { bottom: 0; right: 0; }
/* Pre/code blocks in marketing pages */
.hp-code {
background: var(--hp-term-bg); color: var(--hp-term-ink);
border-radius: var(--hp-radius); border: 1px solid var(--hp-term-line-2);
padding: 14px 16px; overflow-x: auto;
font-family: 'JetBrains Mono', monospace; font-size: 13px; line-height: 1.65;
.hp-code .hp-prompt { color: var(--hp-moss-2); user-select: none; margin-right: 8px; }
.hp-code .hp-arg { color: var(--hp-cyan); }
.hp-code .hp-cmt { color: var(--hp-term-ink-mute); }
.hp-code .hp-flag { color: var(--hp-amber-2); }
/* Small numeric list — used in privacy/terms section bullets */
.hp-numlist { counter-reset: hpnum; padding-left: 0; list-style: none; }
.hp-numlist > li {
counter-increment: hpnum; position: relative;
padding-left: 32px; margin-top: 8px;
.hp-numlist > li::before {
content: '[' counter(hpnum, decimal-leading-zero) ']';
position: absolute; left: 0; top: 0; color: var(--hp-moss);
font-family: 'JetBrains Mono', monospace; font-size: 11px;
font-weight: 600;
/* Yarndings 20 — decorative dingbat face, self-hosted (latin subset,
~4 KB) rather than pulled from the Google Fonts CDN so there's no
render-blocking stylesheet + cross-origin handshake in . The
`font-display: swap` + system-ui fallback keep things sane until the
glyph font loads; the browser only fetches it on pages that render a
`.font-yarndings` element (the branch action-button icons), never on
pages that don't. */
@font-face {
font-family: 'Yarndings 20';
font-style: normal;
font-weight: 400;
font-display: swap;
src: url('/yarndings-20-latin.woff2') format('woff2');
.font-yarndings { font-family: 'Yarndings 20', system-ui, sans-serif; }
